package com.cuzssp.campussecondhandtradingplatform_backend.mapper;import com.cuzssp.campussecondhandtradingplatform_backend.common.entity.OrderInfo;import org.apache.ibatis.annotations.*;import java.util.List;@Mapperpublic interface OrderMapper {    @Select("SELECT * FROM order_info WHERE id = #{id}")    OrderInfo selectById(@Param("id") Long id);    @Select("SELECT * FROM order_info WHERE buyer_id = #{buyerId} ORDER BY created_at DESC")    List<OrderInfo> selectByBuyerId(@Param("buyerId") Long buyerId);    @Select("SELECT * FROM order_info WHERE seller_id = #{sellerId} ORDER BY created_at DESC")    List<OrderInfo> selectBySellerId(@Param("sellerId") Long sellerId);    @Select("SELECT * FROM order_info WHERE status = #{status} ORDER BY created_at DESC")    List<OrderInfo> selectByStatus(@Param("status") Integer status);    @Select("SELECT * FROM order_info")    List<OrderInfo> selectAll();    @Select("SELECT COUNT(*) FROM order_info")    int countAll();    @Select("SELECT COUNT(*) FROM order_info WHERE DATE(created_at) = CURDATE()")    int countTodayNew();    @Insert("INSERT INTO order_info (order_no, buyer_id, seller_id, total_amount, status, remark, created_at, paid_at, shipped_at, completed_at) VALUES (#{orderNo}, #{buyerId}, #{sellerId}, #{totalAmount}, #{status}, #{remark}, #{createdAt}, #{paidAt}, #{shippedAt}, #{completedAt})")    @Options(useGeneratedKeys = true, keyProperty = "id")    int insert(OrderInfo order);    @Update("UPDATE order_info SET order_no=#{orderNo}, buyer_id=#{buyerId}, seller_id=#{sellerId}, total_amount=#{totalAmount}, status=#{status}, remark=#{remark}, paid_at=#{paidAt}, shipped_at=#{shippedAt}, completed_at=#{completedAt} WHERE id=#{id}")    int updateById(OrderInfo order);}